body:
In the following example, we have a similar module `Foo` and `Bar`.  `Foo` has a data tap on it.  `Bar` is later deduplicated with `Foo` and removed.  Some time after this, Tap selects the wrong instance, `bar of Bar` for the DataTap.
```verilog
circuit Top : %[[{
  "class": "sifive.enterprise.grandcentral.DataTapsAnnotation",
  "blackBox": "~Top|DataTap",
  "keys": [
    {
      "class": "sifive.enterprise.grandcentral.ReferenceDataTapKey",
      "source": "~Top|Foo>f",
      "portName": "~Top|DataTap>b"
    }
]}]]
  extmodule DataTap :
    output b : UInt<1>
    defname = DataTap
  module Foo :
    wire f : UInt<1>
    f is invalid
  module Bar :
    wire b : UInt<1>
    b is invalid
  module Top:
    inst foo of Foo
    inst bar of Bar
    inst dataTap of DataTap
```
`./bin/firtool -firrtl-grand-central --dedup ./gc.fir`
```verilog
module DataTap_impl_0(  // ./gc.fir:11:13
  output b);

  assign b = Top.bar.f; // ./gc.fir:11:13
endmodule

module Foo();   // ./gc.fir:14:10, :17:10
  wire f;       // ./gc.fir:15:5, :18:5

  assign f = 1'h0;      // ./gc.fir:16:7, :19:7
endmodule

module Top();   // ./gc.fir:20:10
  wire dataTap_b;       // ./gc.fir:23:5

  Foo foo ();   // ./gc.fir:21:5
  Foo bar ();   // ./gc.fir:22:5
  DataTap_impl_0 dataTap (      // ./gc.fir:23:5
    .b (dataTap_b)
  );
endmodule
```

Some IR dumps:
```mlir
firrtl.circuit "Top"  {
  firrtl.extmodule @DataTap(out b: !firrtl.uint<1> sym @b [{class = "sifive.enterprise.grandcentral.ReferenceDataTapKey", id = 0 : i64, portID = 1 : i64, type = "portName"}]) attributes {annotations = [{class = "sifive.enterprise.grandcentral.DataTapsAnnotation"}, {class = "firrtl.transforms.DontTouchAnnotation"}], defname = "DataTap"}
  firrtl.module @Foo() {
    %f = firrtl.wire sym @f  {annotations = [{class = "sifive.enterprise.grandcentral.ReferenceDataTapKey", id = 0 : i64, portID = 1 : i64, type = "source"}]} : !firrtl.uint<1>
    %invalid_ui1 = firrtl.invalidvalue : !firrtl.uint<1>
    firrtl.connect %f, %invalid_ui1 : !firrtl.uint<1>, !firrtl.uint<1>
  }
  firrtl.module @Bar() {
    %b = firrtl.wire  : !firrtl.uint<1>
    %invalid_ui1 = firrtl.invalidvalue : !firrtl.uint<1>
    firrtl.connect %b, %invalid_ui1 : !firrtl.uint<1>, !firrtl.uint<1>
  }
  firrtl.module @Top() {
    firrtl.instance foo  @Foo()
    firrtl.instance bar  @Bar()
    %dataTap_b = firrtl.instance dataTap  @DataTap(out b: !firrtl.uint<1>)
  }
}

