firrtl.circuit "Top"  {
  firrtl.nla @nla [#hw.innerNameRef<@Top::@foo>, #hw.innerNameRef<@Foo::@f>]
  firrtl.extmodule @DataTap(out b: !firrtl.uint<1> sym @b [{class = "sifive.enterprise.grandcentral.ReferenceDataTapKey", id = 0 : i64, portID = 1 : i64, type = "portName"}]) attributes {annotations = [{class = "sifive.enterprise.grandcentral.DataTapsAnnotation"}, {class = "firrtl.transforms.DontTouchAnnotation"}], defname = "DataTap"}
  firrtl.module @Foo() {
    %f = firrtl.wire sym @f  {annotations = [{circt.nonlocal = @nla, class = "sifive.enterprise.grandcentral.ReferenceDataTapKey", id = 0 : i64, portID = 1 : i64, type = "source"}]} : !firrtl.uint<1>
    %invalid_ui1 = firrtl.invalidvalue : !firrtl.uint<1>
    firrtl.connect %f, %invalid_ui1 : !firrtl.uint<1>, !firrtl.uint<1>
  }
  firrtl.module @Top() {
    firrtl.instance foo sym @foo  {annotations = [{circt.nonlocal = @nla, class = "circt.nonlocal"}]} @Foo()
    firrtl.instance bar  @Foo()
    %dataTap_b = firrtl.instance dataTap  @DataTap(out b: !firrtl.uint<1>)
  }
}

// -----// IR Dump After GrandCentralTaps //----- //
firrtl.circuit "Top"  {
  firrtl.module @DataTap_impl_0(out %b: !firrtl.uint<1> sym @b) attributes {annotations = [{class = "firrtl.transforms.DontTouchAnnotation"}]} {
    %0 = firrtl.verbatim.expr "{{0}}.{{1}}.{{2}}" : () -> !firrtl.uint<1> {symbols = [@Top, #hw.innerNameRef<@Top::@gct_sym>, #hw.innerNameRef<@Foo::@f>]}
    firrtl.connect %b, %0 : !firrtl.uint<1>, !firrtl.uint<1>
  }
  firrtl.module @Foo() {
    %invalid_ui1 = firrtl.invalidvalue : !firrtl.uint<1>
    %f = firrtl.wire sym @f  : !firrtl.uint<1>
    firrtl.strictconnect %f, %invalid_ui1 : !firrtl.uint<1>
  }
  firrtl.module @Top() {
    firrtl.instance foo sym @foo  @Foo()
    firrtl.instance bar sym @gct_sym  @Foo()
    %dataTap_b = firrtl.instance dataTap  @DataTap_impl_0(out b: !firrtl.uint<1>)
  }
}
```
